import{_ as e,o as r,c as o,a2 as a}from"./chunks/framework.0AV_2kjq.js";const u=JSON.parse('{"title":"What is Movi-Player?","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://moviplayer.com/docs/guide/what-is-movi-player"}]]},"headers":[],"relativePath":"guide/what-is-movi-player.md","filePath":"guide/what-is-movi-player.md"}'),i={name:"guide/what-is-movi-player.md"};function l(s,t,d,n,h,p){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="what-is-movi-player" tabindex="-1">What is Movi-Player? <a class="header-anchor" href="#what-is-movi-player" aria-label="Permalink to &quot;What is Movi-Player?&quot;">​</a></h1><p>Movi-Player is a <strong>modern, modular video player</strong> for the web powered by WebCodecs and FFmpeg WASM.</p><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>Traditional web video players have limitations:</p><ul><li>🚫 <strong>Limited Format Support</strong> - Only MP4/WebM with specific codecs</li><li>🚫 <strong>No HDR</strong> - Can&#39;t detect or render HDR content</li><li>🚫 <strong>Server Processing</strong> - Need backend for format conversion</li><li>🚫 <strong>Large Bundle</strong> - All-or-nothing approach</li></ul><h2 id="the-solution" tabindex="-1">The Solution <a class="header-anchor" href="#the-solution" aria-label="Permalink to &quot;The Solution&quot;">​</a></h2><p>Movi-Player solves these problems with:</p><h3 id="🎯-modular-architecture" tabindex="-1">🎯 Modular Architecture <a class="header-anchor" href="#🎯-modular-architecture" aria-label="Permalink to &quot;🎯 Modular Architecture&quot;">​</a></h3><p>Use only what you need:</p><table tabindex="0"><thead><tr><th>Module</th><th>Size</th><th>Use Case</th></tr></thead><tbody><tr><td><code>movi-player/demuxer</code></td><td>~45KB</td><td>Metadata, HDR detection</td></tr><tr><td><code>movi-player/player</code></td><td>~180KB</td><td>Playback control</td></tr><tr><td><code>movi-player</code> (full)</td><td>~410KB</td><td>Complete UI</td></tr></tbody></table><h3 id="⚡-webcodecs-ffmpeg-wasm" tabindex="-1">⚡ WebCodecs + FFmpeg WASM <a class="header-anchor" href="#⚡-webcodecs-ffmpeg-wasm" aria-label="Permalink to &quot;⚡ WebCodecs + FFmpeg WASM&quot;">​</a></h3><ul><li><strong>Hardware acceleration</strong> via WebCodecs API</li><li><strong>Universal fallback</strong> via FFmpeg WASM</li><li><strong>No server required</strong> - all processing in browser</li></ul><h3 id="🌈-hdr-support" tabindex="-1">🌈 HDR Support <a class="header-anchor" href="#🌈-hdr-support" aria-label="Permalink to &quot;🌈 HDR Support&quot;">​</a></h3><ul><li>HDR10, HLG, Dolby Vision metadata extraction</li><li>BT.2020 wide color gamut</li><li>Display-P3 rendering</li></ul><h3 id="📦-universal-format-support" tabindex="-1">📦 Universal Format Support <a class="header-anchor" href="#📦-universal-format-support" aria-label="Permalink to &quot;📦 Universal Format Support&quot;">​</a></h3><ul><li><strong>Containers</strong>: MP4, MKV, WebM, MOV, MPEG-TS</li><li><strong>Video</strong>: H.264, H.265/HEVC, VP9, AV1</li><li><strong>Audio</strong>: AAC, MP3, Opus, FLAC, AC-3</li></ul><h2 id="who-uses-movi-player" tabindex="-1">Who Uses Movi-Player? <a class="header-anchor" href="#who-uses-movi-player" aria-label="Permalink to &quot;Who Uses Movi-Player?&quot;">​</a></h2><p>Movi-Player is ideal for:</p><ul><li>🎬 <strong>Streaming platforms</strong> needing HDR support</li><li>📹 <strong>Video editors</strong> processing local files</li><li>🏥 <strong>Medical imaging</strong> playing DICOM videos</li><li>🎮 <strong>Gaming platforms</strong> showing replays</li><li>📚 <strong>Educational sites</strong> with multi-track support</li></ul><h2 id="browser-support" tabindex="-1">Browser Support <a class="header-anchor" href="#browser-support" aria-label="Permalink to &quot;Browser Support&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Browser</th><th>WebCodecs</th><th>HDR</th></tr></thead><tbody><tr><td>Chrome 94+</td><td>✅</td><td>✅</td></tr><tr><td>Edge 94+</td><td>✅</td><td>✅</td></tr><tr><td>Safari 16.4+</td><td>✅</td><td>✅</td></tr><tr><td>Firefox</td><td>❌</td><td>❌</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Firefox Support</p><p>Firefox WebCodecs support is expected in Q2 2026. Movi-Player will automatically use FFmpeg WASM fallback.</p></div>',22)])])}const m=e(i,[["render",l]]);export{u as __pageData,m as default};
